class Solution:
    def findNthDigit(self, n: int) -> int:
        cnt, len = 1, 1
        while n > len * 9 * cnt:
            n -= len * 9 * cnt
            cnt += 1
            len += 1
        num = int(str(10 ** len - 1 + cnt)[n - 1])
        return num

